const m = $input.item.json;
const clean = s => (s || '').toString().replace(/<[^>]*>/g, ' ').replace(/\s{2,}/g, ' ').trim();
const expediteur = clean(m.from?.value?.[0]?.address || m.From || m.from || '');
const sujet = clean(m.subject || m.Subject || '').substring(0, 300);
const extrait = clean(m.snippet || m.textPlain || m.text || '').substring(0, 1500);
return { json: { message_id: m.id || '', expediteur, sujet, extrait } };

const src = $('Préparer le texte').item.json;
let c;
try { c = JSON.parse($input.item.json.message.content.match(/\{[\s\S]*\}/)[0]); }
catch(e) { c = { est_admin: false }; }
return { json: {
  message_id: src.message_id,
  expediteur: src.expediteur,
  est_admin: c.est_admin === true,
  type: c.type || 'autre',
  libelle: (c.libelle || src.sujet || '').toString().substring(0, 255),
  montant: (typeof c.montant === 'number') ? c.montant : null,
  date_echeance: (c.date_echeance && /^\d{4}-\d{2}-\d{2}$/.test(c.date_echeance)) ? c.date_echeance : null,
  action: (c.action || '').toString().substring(0, 300)
} };
